scripts.mk-scaffold:
node -e "
const fs = require(\"fs\");
const content = [
  \"const fs = require(\\x27fs\\x27);\",
  \"const path = require(\\x27path\\x27);\",
  \"\",
  \"function mkdirp(p) { fs.mkdirSync(p, { recursive: true }); }\",
  \"function write(p, c) { mkdirp(path.dirname(p)); fs.writeFileSync(p, c); }\",
  \"console.log(\\x27Scaffold starting...\\x27);\",
].join(\"\\n\");
fs.writeFileSync(\"scaffold.js\", content);
console.log(\"scaffold.js created\");
"

scripts.build-scaffold:
node -e "
const fs = require(\"fs\");

// Write build-scaffold.js helper
const helper = \`
const fs = require(\"fs\");
const path = require(\"path\");
function mkdirp(p) { fs.mkdirSync(p, { recursive: true }); }
function write(p, c) { mkdirp(path.dirname(p)); fs.writeFileSync(p, c); console.log(\"Created:\", p); }
\`;

fs.writeFileSync(\"build-scaffold.js\", helper + \"console.log(\\\"helper ready\\\");\");
console.log(\"build-scaffold.js written\");
"

scripts.init-scaffold:
node -e "
const fs = require(\"fs\");
const path = require(\"path\");
function mkdirp(p) { fs.mkdirSync(p, { recursive: true }); }
function write(filePath, content) { mkdirp(path.dirname(filePath)); fs.writeFileSync(filePath, content); console.log(\"Wrote:\", filePath); }

write(\"scaffold.js\", \"const fs = require(\\x27fs\\x27);\nconst path = require(\\x27path\\x27);\nfunction mkdirp(p) { fs.mkdirSync(p, { recursive: true }); }\nfunction write(p, c) { mkdirp(path.dirname(p)); fs.writeFileSync(p, c); console.log(\\x27Wrote:\\x27, p); }\nconsole.log(\\x27scaffold ready\\x27);\n\");
console.log(\"scaffold.js initialized\");
"

